import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed
// Helper function to map weather condition to emoji/icon
const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition.toLowerCase();
  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloudy') || conditionLower.includes('overcast')) return '☁️';
  if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
  if (conditionLower.includes('wind')) return '💨';
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
  return '🌤️'; // default
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  const weatherEmoji = getWeatherEmoji(props.condition);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main weather card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)" align="center">
            {/* City and header */}
            <Heading level={1} color="var(--ggui-color-onSurface)" align="center">
              {props.city}
            </Heading>

            {/* Large temperature display with condition */}
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Text size="4xl" weight="bold" aria-label={`${props.condition} weather condition`}>
                {weatherEmoji}
              </Text>
              <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)" align="center">
                {props.temperature}°{props.unit}
              </Text>
              <Heading level={3} color="var(--ggui-color-onSurfaceVariant)" align="center">
                {props.condition}
              </Heading>
            </Stack>

            {/* Humidity and Wind Speed */}
            <Divider orientation="horizontal" margin="var(--ggui-spacing-4)" />
            <Row gap="var(--ggui-spacing-6)" justify="center" align="center">
              <Stack gap="var(--ggui-spacing-2)" align="center" aria-label="Humidity metric">
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-600)" />
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  Humidity
                </Text>
                <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
                  {props.humidity}%
                </Text>
              </Stack>

              <Stack gap="var(--ggui-spacing-2)" align="center" aria-label="Wind speed metric">
                <Icon name="wind" size={24} color="var(--ggui-color-primary-600)" />
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  Wind Speed
                </Text>
                <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
                  {props.windSpeed} m/s
                </Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-day forecast section */}
        {props.forecast && props.forecast.length > 0 && (
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3} color="var(--ggui-color-onSurface)">
              5-Day Forecast
            </Heading>
            <Row gap="var(--ggui-spacing-3)" wrap justify="start" align="stretch">
              {props.forecast.map((day, index) => (
                <Card
                  key={index}
                  shadow="sm"
                  padding="var(--ggui-spacing-4)"
                  radius="md"
                  style={{ flex: '1 1 calc(20% - var(--ggui-spacing-3))' }}
                >
                  <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                    {day.day && (
                      <Text
                        variant="label"
                        weight="semibold"
                        color="var(--ggui-color-onSurface)"
                        align="center"
                      >
                        {day.day}
                      </Text>
                    )}
                    {day.icon && (
                      <Box aria-label={`${day.icon} weather forecast`}>{day.icon}</Box>
                    )}
                    {(day.high !== undefined || day.low !== undefined) && (
                      <Stack gap="var(--ggui-spacing-1)" align="center">
                        {day.high !== undefined && (
                          <Text
                            variant="body"
                            color="var(--ggui-color-onSurface)"
                            align="center"
                          >
                            <span style={{ fontWeight: 'bold' }}>
                              {day.high}°
                            </span>
                          </Text>
                        )}
                        {day.low !== undefined && (
                          <Text
                            variant="bodySmall"
                            color="var(--ggui-color-onSurfaceVariant)"
                            align="center"
                          >
                            {day.low}°
                          </Text>
                        )}
                      </Stack>
                    )}
                  </Stack>
                </Card>
              ))}
            </Row>
          </Stack>
        )}
      </Stack>
    </Container>
  );
}

