import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation errors
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Validate email format
  const isValidEmail = (emailStr: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(emailStr);
  };

  // Validate step 1 (name and email)
  const validateStep1 = (): boolean => {
    let valid = true;
    if (!name.trim()) {
      setNameError('Name is required');
      valid = false;
    } else {
      setNameError('');
    }
    if (!email.trim()) {
      setEmailError('Email is required');
      valid = false;
    } else if (!isValidEmail(email)) {
      setEmailError('Please enter a valid email address');
      valid = false;
    } else {
      setEmailError('');
    }
    return valid;
  };

  // Handle next button click
  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      if (!validateStep1()) return;
    }
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, name, email]);

  // Handle back button click
  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  // Check if next button should be disabled
  const isNextDisabled = useMemo(() => {
    if (currentStep === 1) {
      return !name.trim() || !email.trim() || !isValidEmail(email);
    }
    if (currentStep === 2) {
      return !satisfaction;
    }
    if (currentStep === 3) {
      return features.length === 0;
    }
    return false;
  }, [currentStep, name, email, satisfaction, features]);

  // Handle feature checkbox change
  const handleFeatureChange = (feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  };

  // Handle final submission
  const handleSubmit = useCallback(() => {
    submit({
      name,
      email,
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments,
    });
  }, [name, email, satisfaction, features, comments, submit]);

  // Render step 1: Name and Email
  const renderStep1 = () => (
    <Stack gap="var(--ggui-spacing-4)" align="stretch">
      <Input
        label="Name"
        placeholder="Enter your name"
        value={name}
        onChange={setName}
        error={nameError}
        required
      />
      <Input
        label="Email"
        type="email"
        placeholder="Enter your email"
        value={email}
        onChange={setEmail}
        error={emailError}
        required
      />
    </Stack>
  );

  // Render step 2: Satisfaction rating
  const renderStep2 = () => {
    const radioOptions = props.satisfactionLabels.map((label, index) => ({
      value: String(index + 1),
      label: label,
    }));
    return (
      <RadioGroup
        label="How satisfied are you with our service?"
        value={satisfaction}
        onChange={setSatisfaction}
        options={radioOptions}
        direction="horizontal"
      />
    );
  };

  // Render step 3: Feature interests
  // Render step 3: Feature interests
  const renderStep3 = () => (
    <Stack gap="var(--ggui-spacing-4)" align="stretch">
      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Which features are you interested in?</Text>
      <Stack gap="var(--ggui-spacing-3)" align="stretch">
        {props.featureOptions.map((feature) => (
          <Checkbox
            key={feature}
            label={feature}
            checked={features.includes(feature)}
            onChange={() => handleFeatureChange(feature)}
          />
        ))}
      </Stack>
    </Stack>
  );

  // Render step 4: Comments
  const renderStep4 = () => (
    <Stack gap="var(--ggui-spacing-4)" align="stretch">
      <TextArea
        label="Additional Comments"
        placeholder="Share any additional feedback or comments..."
        value={comments}
        onChange={setComments}
        maxLength={500}
        showCount
        rows={6}
      />
    </Stack>
  );

  // Render final review step
  const renderReview = () => (
    <Stack gap="var(--ggui-spacing-4)" align="stretch">
      <Card padding="var(--ggui-spacing-4)" shadow="md">
        <Stack gap="var(--ggui-spacing-3)" align="stretch">
          <Heading level={2}>Review Your Answers</Heading>
          <Divider margin="var(--ggui-spacing-2)" />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
            <Text>{name}</Text>
          </Box>
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
            <Text>{email}</Text>
          </Box>
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction Rating</Text>
             <Text>
               {satisfaction ? props.satisfactionLabels[parseInt(satisfaction, 10) - 1] : 'Not selected'}
             </Text>
          </Box>
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Interested Features</Text>
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal" wrap align="start">
              {features.length > 0 ? (
                features.map((feature) => (
                  <Badge key={feature} variant="primary">{feature}</Badge>
                ))
              ) : (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">None selected</Text>
              )}
            </Stack>
          </Box>
          {comments && (
            <Box>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
              <Text>{comments}</Text>
            </Box>
          )}
        </Stack>
      </Card>
    </Stack>
  );

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Progress bar */}
        <Stack gap="var(--ggui-spacing-2)" align="stretch">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" aria-live="polite" aria-atomic="true">
            Step {currentStep} of 4
          </Text>
          <Progress
            value={currentStep}
            max={4}
            variant="default"
            size="md"
          />
        </Stack>

        {/* Step content */}
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)" align="stretch">
            {currentStep === 1 && (
              <>
                <Heading level={2}>Personal Information</Heading>
                {renderStep1()}
              </>
            )}
            {currentStep === 2 && (
              <>
                <Heading level={2}>Satisfaction Rating</Heading>
                {renderStep2()}
              </>
            )}
            {currentStep === 3 && (
              <>
                <Heading level={2}>Feature Interests</Heading>
                {renderStep3()}
              </>
            )}
            {currentStep === 4 && (
              <>
                <Heading level={2}>Additional Comments</Heading>
                {renderStep4()}
              </>
            )}
            {currentStep === 5 && (
              <>
                {renderReview()}
              </>
            )}
          </Stack>
        </Card>

        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
            {currentStep < 4 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={isNextDisabled}
              >
                Next
              </Button>
            )}
            {currentStep === 4 && (
              <Button
                variant="primary"
                onClick={() => {
                  setCurrentStep(5);
                }}
              >
                Review
              </Button>
            )}
            {currentStep === 5 && (
              <Button
                variant="primary"
                onClick={handleSubmit}
              >
                Submit Survey
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}

