import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Task card component for individual task display
function TaskCard({
  task,
  columnId,
  onMove,
  onEdit,
}: {
  task: Props['tasks'][0];
  columnId: string;
  onMove: (taskId: string, newColumn: string) => void;
  onEdit: (taskId: string, newTitle: string) => void;
}) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);

  const handleSave = () => {
    if (editTitle.trim()) {
      onEdit(task.id || '', editTitle.trim());
      setIsEditing(false);
    }
  };

  const handleCancel = () => {
    setEditTitle(task.title || '');
    setIsEditing(false);
  };

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'var(--ggui-color-error-500)';
      case 'medium':
        return 'var(--ggui-color-warning-500)';
      case 'low':
        return 'var(--ggui-color-success-500)';
      default:
        return 'var(--ggui-color-outline)';
    }
  };

  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  return (
    <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-3)">
        {isEditing ? (
          <Stack gap="var(--ggui-spacing-2)">
            <Input
              label="Task title"
              value={editTitle}
              onChange={setEditTitle}
              autoFocus
            />
            <Row gap="var(--ggui-spacing-2)" justify="end">
              <Button variant="ghost" size="sm" onClick={handleCancel}>
                Cancel
              </Button>
              <Button variant="primary" size="sm" onClick={handleSave}>
                Save
              </Button>
            </Row>
          </Stack>
        ) : (
          <Stack gap="var(--ggui-spacing-3)">
            <Row align="center" justify="between">
              <Text
                variant="body"
                weight="medium"
                truncate
                as={Clickable}
                onClick={() => setIsEditing(true)}
                aria-label={`Double-click to edit task title: ${task.title || 'Untitled Task'}`}
              >
                {task.title || 'Untitled Task'}
              </Text>
              <Button
                variant="ghost"
                size="xs"
                rightIcon={<Icon name="edit-2" size={14} />}
                onClick={() => setIsEditing(true)}
                aria-label="Edit task title"
              />
            </Row>
            {task.priority && (
              <Badge variant={getPriorityVariant(task.priority)} size="sm">
                {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
              </Badge>
            )}
            {task.assignee && (
              <Row align="center" gap="var(--ggui-spacing-2)">
                <Avatar
                  name={task.assignee}
                  size="sm"
                  shape="circle"
                  aria-label={`Assignee: ${task.assignee}`}
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {task.assignee}
                </Text>
              </Row>
            )}
            {task.dueDate && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Due: {new Date(task.dueDate).toLocaleDateString()}
              </Text>
            )}
            <Row gap="var(--ggui-spacing-2)" justify="end">
              <Dropdown
                trigger={
                  <Button variant="ghost" size="xs" rightIcon={<Icon name="chevron-down" size={14} />} aria-label="Move task to another column">
                    Move
                  </Button>
                }
                options={[
                  { value: 'todo', label: 'To Do' },
                  { value: 'in-progress', label: 'In Progress' },
                  { value: 'done', label: 'Done' },
                ]}
                value={columnId}
                onChange={(newColumn) => {
                  onMove(task.id || '', newColumn);
                  setShowMoveMenu(false);
                }}
                placement="bottom-end"
              />
            </Row>
          </Stack>
        )}
      </Stack>
    </Card>
  );
}
export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // State for local task management
  const [tasks, setTasks] = useState(props.tasks || []);
  const [newTaskInputs, setNewTaskInputs] = useState<Record<string, { title: string; priority: string; assignee: string; dueDate: string }>>({});
  // Update local tasks when props change
  useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  // Update tasks when stream events arrive
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setTasks((prev) => [...prev, task]);
      } else if (action === 'move' && task) {
        setTasks((prev) =>
          prev.map((t) => (t.id === task.id ? { ...t, column: task.column } : t))
        );
      } else if (action === 'edit' && task) {
        setTasks((prev) =>
          prev.map((t) => (t.id === task.id ? { ...t, title: task.title } : t))
        );
      } else if (action === 'delete' && task) {
        setTasks((prev) => prev.filter((t) => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  // Compute tasks grouped by column
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof tasks> = {};
    (props.columns || []).forEach((col) => {
      grouped[col.id || ''] = tasks.filter((t) => t.column === col.id);
    });
    return grouped;
  }, [tasks, props.columns]);

  // Compute task counts
  const taskCounts = useMemo(() => {
    const completed = tasks.filter((t) => t.column === 'done').length;
    const total = tasks.length;
    return { completed, total };
  }, [tasks]);

  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t))
      );
      taskUpdate({
        action: 'move',
        taskId,
        data: { column: newColumn },
      });
    },
    [taskUpdate]
  );

  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
      );
       taskUpdate({
         action: 'edit',
         taskId,
         data: { title: newTitle, column: tasks.find((t) => t.id === taskId)?.column || '' },
       });
    },
    [taskUpdate, tasks]
  );

  const handleCreateTask = useCallback(
    (columnId: string) => {
      const inputData = newTaskInputs[columnId];
      if (!inputData?.title?.trim()) return;

      const newTask = {
        id: `task-${Date.now()}`,
        title: inputData.title.trim(),
        priority: (inputData.priority || 'medium') as 'low' | 'medium' | 'high',
        assignee: inputData.assignee || undefined,
        dueDate: inputData.dueDate || undefined,
        column: columnId,
      };

      setTasks((prev) => [...prev, newTask]);
      taskUpdate({
        action: 'create',
        taskId: newTask.id,
        data: { column: columnId },
      });

      setNewTaskInputs((prev) => ({ ...prev, [columnId]: { title: '', priority: 'medium', assignee: '', dueDate: '' } }));
    },
    [newTaskInputs, taskUpdate]
  );

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={1}>Task Board</Heading>
          <Card padding="var(--ggui-spacing-4)" shadow="sm">
            <Row gap="var(--ggui-spacing-4)" align="center">
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Total Tasks
                </Text>
                <Text variant="bodyLarge" weight="bold">
                  {taskCounts.total}
                </Text>
              </Box>
              <Divider orientation="vertical" margin="var(--ggui-spacing-0)" />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Completed
                </Text>
                <Text variant="bodyLarge" weight="bold">
                  {taskCounts.completed}
                </Text>
              </Box>
              <Spacer size="flex" />
              <Progress
                value={taskCounts.total > 0 ? (taskCounts.completed / taskCounts.total) * 100 : 0}
                variant="success"
                size="md"
              />
            </Row>
          </Card>
        </Stack>

        {/* Kanban Board */}
        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {(props.columns || []).map((column) => (
            <Box key={column.id} flex={`0 1 calc(33.333% - var(--ggui-spacing-3))`} minWidth="300px">
              <Stack gap="var(--ggui-spacing-3)">
                {/* Column Header */}
                <Card padding="var(--ggui-spacing-4)" shadow="none" border={false}>
                  <Row align="center" justify="between">
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                      <Heading level={4}>{column.name}</Heading>
                      <Badge variant="secondary" size="md">
                        {tasksByColumn[column.id || '']?.length || 0}
                      </Badge>
                    </Stack>
                  </Row>
                </Card>

                {/* Task List */}
                <Stack gap="var(--ggui-spacing-3)" align="stretch">
                  {(tasksByColumn[column.id || ''] || []).map((task) => (
                    <TaskCard
                      key={task.id}
                      task={task}
                      columnId={column.id || ''}
                      onMove={handleMoveTask}
                      onEdit={handleEditTask}
                    />
                  ))}
                </Stack>

                {/* Add Task Form — only show in To Do column */}
                {column.id === 'todo' && (
                <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Input
                      label="New task title"
                      placeholder="Type task title..."
                      value={newTaskInputs[column.id || '']?.title || ''}
                      onChange={(val) =>
                        setNewTaskInputs((prev) => ({
                          ...prev,
                          [column.id || '']: { ...prev[column.id || ''] || { title: '', priority: 'medium', assignee: '', dueDate: '' }, title: val },
                        }))
                      }
                      size="sm"
                    />
                    <Select
                      label="Priority"
                      value={newTaskInputs[column.id || '']?.priority || 'medium'}
                      onChange={(val) =>
                        setNewTaskInputs((prev) => ({
                          ...prev,
                          [column.id || '']: { ...prev[column.id || ''] || { title: '', priority: 'medium', assignee: '', dueDate: '' }, priority: val },
                        }))
                      }
                      options={[
                        { value: 'low', label: 'Low' },
                        { value: 'medium', label: 'Medium' },
                        { value: 'high', label: 'High' },
                      ]}
                      size="sm"
                    />
                    <Input
                      label="Assignee"
                      placeholder="Initials or name..."
                      value={newTaskInputs[column.id || '']?.assignee || ''}
                      onChange={(val) =>
                        setNewTaskInputs((prev) => ({
                          ...prev,
                          [column.id || '']: { ...prev[column.id || ''] || { title: '', priority: 'medium', assignee: '', dueDate: '' }, assignee: val },
                        }))
                      }
                      size="sm"
                    />
                    <Input
                      label="Due Date"
                      type="date"
                      value={newTaskInputs[column.id || '']?.dueDate || ''}
                      onChange={(val) =>
                        setNewTaskInputs((prev) => ({
                          ...prev,
                          [column.id || '']: { ...prev[column.id || ''] || { title: '', priority: 'medium', assignee: '', dueDate: '' }, dueDate: val },
                        }))
                      }
                      size="sm"
                    />
                    <Button
                      variant="primary"
                      size="sm"
                      fullWidth
                      onClick={() => handleCreateTask(column.id || '')}
                    >
                      + Add Task
                    </Button>
                  </Stack>
                </Card>
                )}
              </Stack>
            </Box>
           ))}
         </Row>
       </Stack>
     </Container>
   );
}

