      (el.name?.toLowerCase().includes(query) ?? false)
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set(props.elements.map(el => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [props.elements]);

  // Category color mapping
  const categoryColors: Record<string, string> = {
    'alkali-metal': 'var(--ggui-color-primary-100)',
    'alkaline-earth': 'var(--ggui-color-primary-200)',
    'transition-metal': 'var(--ggui-color-warning-100)',
    'lanthanide': 'var(--ggui-color-info-100)',
    'actinide': 'var(--ggui-color-error-100)',
    'nonmetal': 'var(--ggui-color-success-100)',
    'halogen': 'var(--ggui-color-warning-200)',
    'noble-gas': 'var(--ggui-color-info-200)',
  };

  const getElementColor = (category?: string) => categoryColors[category!] || 'var(--ggui-color-surfaceVariant)';

  return (
