              <Row justify="between" align="center">
                <Heading level={3}>{selectedElement.name}</Heading>
                <Button variant="ghost" onClick={() => setSelectedElement(null)}>
                  ✕
                </Button>
              </Row>
              <Stack gap="var(--ggui-spacing-2)">
                <Row justify="between">
                  <Text variant="label">Symbol:</Text>
                  <Text>{selectedElement.symbol}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label">Atomic Number:</Text>
                  <Text>{selectedElement.atomicNumber}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label">Atomic Weight:</Text>
                  <Text>{selectedElement.atomicWeight?.toFixed(3)}</Text>
