            currentMarketStatus === 'after-hours' ? 'info' :
            'default'
          }>
            Market: {currentMarketStatus}
          </Badge>
        </Stack>


        {/* Stock Cards Grid */}
        {stocks && stocks.length > 0 ? (
          <Box
            style={{
