  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [boardTasks, setBoardTasks] = useState<BoardTask[]>([]);
  const [showAddFormByColumn, setShowAddFormByColumn] = useState<Record<string, boolean>>({});
  const [newTaskTitleByColumn, setNewTaskTitleByColumn] = useState<Record<string, string>>({});
  const [newTaskPriorityByColumn, setNewTaskPriorityByColumn] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [actionError, setActionError] = useState<string>('');
  const [streamStatusMessage, setStreamStatusMessage] = useState<string>('');
  useEffect(() => {
    const normalized = (props.tasks || []).map((task, index) => normalizeTask(task, index, props.columns || []));
    setBoardTasks(normalized);
  }, [props.tasks, props.columns]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incoming = normalizeTask(taskChanged.latest.task, boardTasks.length + 1, props.columns || []);
    setBoardTasks((prev) => {
      if (taskChanged.latest?.action === 'delete') {
        return prev.filter((t) => t.id !== incoming.id);
      }
      const existingIndex = prev.findIndex((t) => t.id === incoming.id);
      if (existingIndex === -1) return [...prev, incoming];
      const next = [...prev];
      next[existingIndex] = { ...next[existingIndex], ...incoming };
      return next;
    });
  }, [taskChanged.latest, props.columns, boardTasks.length]);

  const orderedColumns = useMemo(() => {
    const safeColumns = props.columns || [];
    const byKnown = COLUMN_ORDER.map((id) => safeColumns.find((c) => c.id === id)).filter(Boolean) as Array<{ id?: string; name?: string }>;
    const extras = safeColumns.filter((c) => !COLUMN_ORDER.includes(c.id || ''));
    return [...byKnown, ...extras];
  }, [props.columns]);

  const totalTasks = boardTasks.length;
  const completedColumnId = (orderedColumns.find((c) => String(c.name || '').toLowerCase() === 'done')?.id) || 'done';
  const completedTasks = boardTasks.filter((task) => task.column === completedColumnId).length;
  const defaultTodoColumnId = orderedColumns.find((col) => String(col.name || '').toLowerCase() === 'to do')?.id || 'todo';
  const moveTask = useCallback(
    (taskId: string, targetColumn: string) => {
      setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: targetColumn } : task)));
      try {
        taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
        setActionError('');
      } catch (_error) {
        setActionError('Could not sync task move. Please retry.');
      }
    },
    [taskUpdate]
  );

  const startEditTask = useCallback((taskId: string, title: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(title);
  }, []);

  const saveEditTask = useCallback(
    (taskId: string) => {
      const nextTitle = editingTitle.trim();
      if (!nextTitle) return;
      setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: nextTitle } : task)));
      const current = boardTasks.find((task) => task.id === taskId);
      try {
        taskUpdate({ action: 'edit', taskId, data: { column: current?.column || 'todo', title: nextTitle, priority: current?.priority || 'low', assignee: current?.assignee || 'NA', dueDate: current?.dueDate } });
        setActionError('');
      } catch (_error) {
        setActionError('Could not sync task edit. Please retry.');
      }
      setEditingTaskId('');
      setEditingTitle('');
    },
    [editingTitle, boardTasks, taskUpdate]
  );

  const addTaskToColumn = useCallback(
    (columnId?: string) => {
      const targetColumnId = columnId || defaultTodoColumnId;
      const title = (newTaskTitleByColumn[targetColumnId] || '').trim();
      if (!title) return;
      const priority = newTaskPriorityByColumn[targetColumnId] || 'low';
      const id = `task-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
      const newTask: BoardTask = {
        id,
        title,
        priority,
        assignee: 'NA',
        column: targetColumnId,
      };
      setBoardTasks((prev) => [...prev, newTask]);
      try {
        taskUpdate({ action: 'create', taskId: id, data: { column: newTask.column, title: newTask.title, priority: newTask.priority, assignee: newTask.assignee, dueDate: newTask.dueDate } });
        setActionError('');
      } catch (_error) {
        setActionError('Could not sync new task creation. Please retry.');
      }
      setNewTaskTitleByColumn((prev) => ({ ...prev, [targetColumnId]: '' }));
      setNewTaskPriorityByColumn((prev) => ({ ...prev, [targetColumnId]: 'low' }));
      setShowAddFormByColumn((prev) => ({ ...prev, [targetColumnId]: false }));
    },
    [newTaskTitleByColumn, newTaskPriorityByColumn, taskUpdate, defaultTodoColumnId]
  );

  useEffect(() => {
    setStreamStatusMessage(taskChanged.latest ? '' : 'Live updates unavailable. Waiting for stream…');
  }, [taskChanged.latest]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Team Kanban Board</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">
                Track progress across columns with live updates
              </Text>
            </Stack>
            <Row gap="var(--ggui-spacing-3)">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedTasks}</Badge>
            </Row>
          </Row>
        </Card>

        {!props.columns || props.columns.length === 0 ? (
          <Alert variant="warning" title="No columns configured">
            Add columns in your data source to use the board.
          </Alert>
        ) : null}

        {actionError ? (
          <Alert variant="error" title="Sync issue">
            {actionError} Check your connection and try the action again.
          </Alert>
        ) : null}

        {streamStatusMessage ? (
          <Alert variant="warning" title="Realtime status">
            {streamStatusMessage}
          </Alert>
        ) : null}

        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {(orderedColumns || []).map((column) => {
            const columnId = column.id || 'unknown';
            const columnTasks = (boardTasks || []).filter((task) => task.column === columnId);
            return (
              <Card
                key={columnId}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                border
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={4}>{column.name || 'Untitled Column'}</Heading>
                    <Badge variant="default">{columnTasks.length}</Badge>
                  </Row>

                  {(columnTasks || []).length === 0 ? (
                    <Box
                      padding="var(--ggui-spacing-3)"
                      background="var(--ggui-color-surfaceVariant)"
                      borderRadius="var(--ggui-shape-radius-md)"
                    >
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        No tasks in this column.
                      </Text>
                    </Box>
                  ) : null}

                  <Stack gap="var(--ggui-spacing-3)">
                    {(columnTasks || []).map((task) => {
                      return (
                        <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="none" border>
                          <Stack gap="var(--ggui-spacing-2)">
                            <Row justify="between" align="center">
                              {editingTaskId === task.id ? (
                                <Input
                                  label="Edit task title"
                                  value={editingTitle}
                                  onChange={setEditingTitle}
                                  placeholder="Task title"
                                />
                              ) : (
                                <Text
                                  as={Clickable}
                                  onClick={() => {}}
                                  onDoubleClick={() => startEditTask(task.id, task.title)}
                                  is="span"
                                  weight="medium"
                                  color="var(--ggui-color-onSurface)"
                                >
                                  {task.title}
                                </Text>
                              )}
                              <Badge variant={getPriorityBadgeVariant(task.priority)}>{task.priority}</Badge>
                            </Row>

                            <Row justify="between" align="center">
                              <Row gap="var(--ggui-spacing-2)" align="center">
                                <Avatar name={task.assignee || 'NA'} size="sm" />
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  {task.assignee || 'NA'}
                                </Text>
                              </Row>
                              {task.dueDate ? (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  Due: {task.dueDate}
                                </Text>
                              ) : (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  No due date
                                </Text>
                              )}
                            </Row>

                            <Row gap="var(--ggui-spacing-2)" align="center">
                              {editingTaskId === task.id ? (
                                <>
                                  <Button variant="primary" size="sm" onPress={() => saveEditTask(task.id)}>Save</Button>
                                  <Button variant="ghost" size="sm" onPress={() => { setEditingTaskId(''); setEditingTitle(''); }}>Cancel</Button>
                                </>
                              ) : (
                                <Button variant="outline" size="sm" onPress={() => startEditTask(task.id, task.title)}>Edit</Button>
                              )}
                              <Select
                                label="Move task"
                                value={task.column}
                                onChange={(value) => moveTask(task.id, value)}
                                options={(orderedColumns || []).map((col) => ({ value: col.id || '', label: col.name || 'Untitled' }))}
                              />
                            </Row>
