function normalizeCategory(category?: string): string {
  return (category || 'unknown').toLowerCase().trim().replace(/[_\s-]+/g, ' ');
}

function categoryColor(category?: string): string {
  const key = normalizeCategory(category);
  const map: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-error-100)',
    'alkaline earth metal': 'var(--ggui-color-warning-100)',
    'transition metal': 'var(--ggui-color-primary-100)',
    'post-transition metal': 'var(--ggui-color-primary-200)',
    metalloid: 'var(--ggui-color-success-100)',
    nonmetal: 'var(--ggui-color-success-200)',
    halogen: 'var(--ggui-color-warning-200)',
    'noble gas': 'var(--ggui-color-info-100)',
    lanthanide: 'var(--ggui-color-primary-50)',
    actinide: 'var(--ggui-color-error-50)',
    unknown: 'var(--ggui-color-surfaceVariant)',
  };
  return map[key] || 'var(--ggui-color-surfaceVariant)';
}

