              <Text size="xl" weight="bold" color="var(--ggui-color-primary-700)">{formattedPrice}</Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                {renderStars(normalizedRating, `Rated ${normalizedRating} out of 5`)}
