                  ({typeof props.product?.reviewCount === 'number' ? props.product.reviewCount : 0})
                </Text>
              </Row>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Badge variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}>
                  {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
                </Badge>
                <Text color="var(--ggui-color-onSurfaceVariant)">
                  {typeof props.product?.stock === 'number' ? props.product.stock : 0} available
                </Text>
              </Row>
            </Stack>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Text color="var(--ggui-color-onSurfaceVariant)">
                    {props.product?.description ?? 'No description available.'}
                  </Text>
                ),
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: specificationRows.length > 0 ? (
                  <Table
                    columns={[
                      { key: 'key', header: 'Specification' },
                      { key: 'value', header: 'Value' },
                    ]}
                    data={specificationRows}
                  />
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available.</Text>
                ),
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: reviews.length > 0 ? (
                  <Stack gap="var(--ggui-spacing-4)">
                    {reviews.map((review) => (
                      <Card key={review.id} padding="var(--ggui-spacing-4)" border shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Row justify="between" align="center">
                            <Text weight="semibold">{review.author}</Text>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date}</Text>
                          </Row>
                          {renderStars(review.rating)}
                          <Text color="var(--ggui-color-onSurfaceVariant)">{review.text || 'No review text provided.'}</Text>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>
                ),
              },
            ]}
          />
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>Purchase</Heading>
            <Row gap="var(--ggui-spacing-3)" align="center" wrap>
              <Input
                label="Quantity"
                type="number"
                value={String(quantity)}
                onChange={(value) => {
                  const parsed = Number(value);
                  const maxStock = typeof props.product?.stock === 'number' ? props.product.stock : 0;
                  if (Number.isNaN(parsed)) return;
                  if (maxStock <= 0) {
                    setQuantity(1);
                    return;
                  }
                  setQuantity(Math.max(1, Math.min(maxStock, Math.round(parsed))));
                }}
                disabled={isOutOfStock}
              />
              <Button
                variant="outline"
                size="sm"
                aria-label="Increase quantity"
                disabled={isOutOfStock || quantity >= (typeof props.product?.stock === 'number' ? props.product.stock : 0)}
                onClick={() => {
                  const maxStock = typeof props.product?.stock === 'number' ? props.product.stock : 0;
                  if (maxStock > 0) setQuantity((prev) => Math.min(maxStock, prev + 1));
                }}
              >
                +
              </Button>
              <Button variant="primary" disabled={isOutOfStock || !props.product?.id} onClick={handleAddToCart}>
                Add to Cart
              </Button>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

