          </Row>
        </Card>

        {(!displayStocks || displayStocks.length === 0) && (
          <Alert variant="info" title="No stocks available">
            Waiting for initial stock data or live price updates.
          </Alert>
        )}

        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {(displayStocks || []).map((stock) => {
            const changeValue = stock.change ?? 0;
            const percentValue = stock.changePercent ?? 0;
            const isPositive = changeValue >= 0;
            const color = isPositive ? 'var(--ggui-color-success-700)' : 'var(--ggui-color-error-700)';
            const borderColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
            const symbolKey = stock.symbol || stock.name || 'UNKNOWN';
            const flashKey = flashMap[symbolKey] || 0;

            return (
              <Card
                key={`${symbolKey}-${flashKey}`}
                padding="var(--ggui-spacing-4)"
                border
                shadow="sm"
                style={{
                  borderColor,
                  animation: 'ggui-flash 500ms ease-out',
                  ['--ggui-flash-color' as string]: isPositive ? 'var(--ggui-color-success-100)' : 'var(--ggui-color-error-100)',
                }}
              >
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={3} color="var(--ggui-color-onSurface)">{stock.symbol || '—'}</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    {stock.name || 'Unknown Company'}
                  </Text>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
                    ${formatPrice(stock.price)}
                  </Text>
                  <Row justify="between" align="center">
                    <Text variant="bodySmall" color={color}>
                      {formatSigned(changeValue)}
                    </Text>
                    <Row align="center" gap="var(--ggui-spacing-1)">
                      <Text variant="bodySmall" color={color}>
                        {isPositive ? '▲' : '▼'}
                      </Text>
                      <Text variant="bodySmall" color={color}>
                        {formatSignedPercent(percentValue)}
                      </Text>
                    </Row>
                  </Row>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const normalizedAvatarOptions = useMemo(() => {
    if (props.avatarOptions && props.avatarOptions.length > 0) {
      return props.avatarOptions.slice(0, 4);
    }
    return ['😀', '🚀', '🎨', '🧠'];
  }, [props.avatarOptions]);

  const normalizedRoleOptions = useMemo(() => {
    if (props.roleOptions && props.roleOptions.length > 0) {
      return props.roleOptions;
    }
    return ['Developer', 'Designer', 'Manager', 'Other'];
  }, [props.roleOptions]);

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name || '');
  const [email, setEmail] = useState(props.initialProfile?.email || '');
  const [avatar, setAvatar] = useState(
    props.initialProfile?.avatar || normalizedAvatarOptions[0] || '😀',
  );
  const [role, setRole] = useState(props.initialProfile?.role || '');
  const [emailNotifications, setEmailNotifications] = useState(
    props.initialProfile?.emailNotifications ?? true,
  );
  const [theme, setTheme] = useState(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');
  const [submittedStepOne, setSubmittedStepOne] = useState(false);

  useEffect(() => {
    if (!avatar && normalizedAvatarOptions.length > 0) {
      setAvatar(normalizedAvatarOptions[0]);
    }
  }, [avatar, normalizedAvatarOptions]);

  const nameError = useMemo(() => {
    if (!submittedStepOne) return '';
    if (!name.trim()) return 'Name is required.';
    return '';
  }, [name, submittedStepOne]);

  const emailError = useMemo(() => {
    if (!submittedStepOne) return '';
    if (!email.trim()) return 'Email is required.';
    if (!EMAIL_REGEX.test(email.trim())) return 'Please enter a valid email address.';
    return '';
  }, [email, submittedStepOne]);

  const isStepOneValid = useMemo(() => {
    return Boolean(name.trim()) && EMAIL_REGEX.test(email.trim()) && Boolean(avatar);
  }, [name, email, avatar]);

  const canProceed = useMemo(() => {
    if (step === 1) return isStepOneValid;
    if (step === 2) return true;
    return false;
  }, [step, isStepOneValid]);

  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setSubmittedStepOne(true);
      if (!isStepOneValid) return;
    }
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [step, isStepOneValid]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleComplete = useCallback(() => {
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar: avatar || (normalizedAvatarOptions[0] || '😀'),
      role: role || 'Other',
      emailNotifications,
      theme,
    };
    complete(payload);
    if (typeof (props as { onComplete?: (data: ActionCompletePayload) => void }).onComplete === 'function') {
      (props as { onComplete?: (data: ActionCompletePayload) => void }).onComplete?.(payload);
    }
  }, [name, email, avatar, role, emailNotifications, theme, complete, normalizedAvatarOptions, props]);

  const roleSelectOptions = useMemo(() => {
    return normalizedRoleOptions.map((option) => ({ value: option, label: option }));
  }, [normalizedRoleOptions]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={2}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" showLabel />
            <Row gap="var(--ggui-spacing-2)">
              <Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Box
            key={step}
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your full name"
                  required
                  error={nameError || undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={emailError || undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose an avatar</Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {normalizedAvatarOptions.map((option) => {
                      const selected = avatar === option;
                      return (
                        <Card
                          key={option}
                          as={Clickable}
                          onClick={() => setAvatar(option)}
                          aria-label={`Select avatar ${option}`}
                          aria-pressed={selected}
                          padding="var(--ggui-spacing-3)"
                          border
                          shadow="none"
                          style={{
                            borderColor: selected ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                            background: selected ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                            transition: 'all 200ms ease-in-out',
                            minWidth: '64px',
                          }}
                        >
                          <Stack align="center" gap="var(--ggui-spacing-1)">
                            <Text size="2xl" is="span">{option}</Text>
                            {selected && <Badge variant="primary" size="sm">Selected</Badge>}
                          </Stack>
                        </Card>
                      );
                    })}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={roleSelectOptions}
                  placeholder="Select your role"
                  helperText="You can update this later in settings."
                />
                <Toggle
                  label="Enable email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Review & Confirm</Heading>
                <Alert variant="info" title="Please review your details">
                  Confirm your information before completing setup.
                </Alert>
                <Card padding="var(--ggui-spacing-4)" shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row align="start" gap="var(--ggui-spacing-3)"><Box style={{ flex: '0 0 180px' }}><Text variant="label">Name</Text></Box><Box style={{ flex: 1, minWidth: 0 }}><Text>{name || '-'}</Text></Box></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row align="start" gap="var(--ggui-spacing-3)"><Box style={{ flex: '0 0 180px' }}><Text variant="label">Email</Text></Box><Box style={{ flex: 1, minWidth: 0 }}><Text>{email || '-'}</Text></Box></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row align="start" gap="var(--ggui-spacing-3)"><Box style={{ flex: '0 0 180px' }}><Text variant="label">Avatar</Text></Box><Box style={{ flex: 1, minWidth: 0 }}><Text>{avatar || '-'}</Text></Box></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row align="start" gap="var(--ggui-spacing-3)"><Box style={{ flex: '0 0 180px' }}><Text variant="label">Role</Text></Box><Box style={{ flex: 1, minWidth: 0 }}><Text>{role || 'Other'}</Text></Box></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row align="start" gap="var(--ggui-spacing-3)"><Box style={{ flex: '0 0 180px' }}><Text variant="label">Email Notifications</Text></Box><Box style={{ flex: 1, minWidth: 0 }}><Text>{emailNotifications ? 'On' : 'Off'}</Text></Box></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row align="start" gap="var(--ggui-spacing-3)"><Box style={{ flex: '0 0 180px' }}><Text variant="label">Theme</Text></Box><Box style={{ flex: 1, minWidth: 0 }}><Text>{theme === 'dark' ? 'Dark' : 'Light'}</Text></Box></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-5)" />

          <Row justify="between" align="center">
            <Button variant="outline" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>
            <Row gap="var(--ggui-spacing-2)">
              {step < 3 && (
                <Button variant="primary" onClick={handleNext} disabled={!canProceed}>
                  Next
                </Button>
              )}
              {step === 3 && (
                <>
                  <Button variant="secondary" onClick={handleBack}>
                    Go Back
                  </Button>
                  <Button variant="primary" onClick={handleComplete}>
                    Complete Setup
                  </Button>
                </>
              )}
            </Row>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
